package basics;

public class Loop {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		for(int counter = 1;counter<=100 ;counter++)
		{
			System.out.println("Test case " +counter);
		}

	
	int i = 1;
	while(i<=5) {
		System.out.println(i);
		i++;
	}

}
}